// Test manual ZIP extraction of Switch.xml using pure Node.js \(no external deps\)
const { readFileSync } = require\('fs'\);
const zlib = require\('zlib'\);

const buf = readFileSync\('Switch.mpk'\);

// Find local file header for Switch.xml
let offset = 0;
while \(offset < buf.length\) {
  const sig = buf.readUInt32LE\(offset\);
  if \(sig !== 0x04034b50\) break; // Not a local file header

  const compressionMethod = buf.readUInt16LE\(offset + 8\);
  const compressedSize = buf.readUInt32LE\(offset + 18\);
  const uncompressedSize = buf.readUInt32LE\(offset + 22\);
  const fileNameLen = buf.readUInt16LE\(offset + 26\);
  const extraLen = buf.readUInt16LE\(offset + 28\);
  const fileName = buf.toString\('utf-8', offset + 30, offset + 30 + fileNameLen\);

  const dataOffset = offset + 30 + fileNameLen + extraLen;

  if \(fileName === 'Switch.xml'\) {
    console.log\('Found Switch.xml! compression:', compressionMethod, 'compressed:', compressedSize, 'uncompressed:', uncompressedSize\);

    if \(compressionMethod === 0\) {
      // Stored \(no compression\)
      console.log\(buf.toString\('utf-8', dataOffset, dataOffset + compressedSize\)\);
    } else if \(compressionMethod === 8\) {
      // Deflate
      const compressed = buf.slice\(dataOffset, dataOffset + compressedSize\);
      const decompressed = zlib.inflateRawSync\(compressed\);
      console.log\(decompressed.toString\('utf-8'\)\);
    }
    break;
  }

  offset = dataOffset + compressedSize;
}
")

