const fs = require\('fs'\);
const zlib = require\('zlib'\);
const buf = fs.readFileSync\('Switch.mpk'\);

function readZipEntry\(buf, fileName\) {
  let eocdOff = -1;
  for \(let i = buf.length - 22; i >= 0; i--\) {
    if \(buf.readUInt32LE\(i\) === 0x06054b50\) { eocdOff = i; break; }
  }
  const cdOff = buf.readUInt32LE\(eocdOff + 16\);
  const totalEntries = buf.readUInt16LE\(eocdOff + 10\);

  let off = cdOff;
  for \(let i = 0; i < totalEntries; i++\) {
    const nameLen = buf.readUInt16LE\(off + 28\);
    const extraLen = buf.readUInt16LE\(off + 30\);
    const commentLen = buf.readUInt16LE\(off + 32\);
    const name = buf.toString\('utf-8', off + 46, off + 46 + nameLen\);
    const localOff = buf.readUInt32LE\(off + 42\);
    const method = buf.readUInt16LE\(off + 10\);
    const compSize = buf.readUInt32LE\(off + 20\);

    if \(name === fileName\) {
      // Read local file header
      const localNameLen = buf.readUInt16LE\(localOff + 26\);
      const localExtraLen = buf.readUInt16LE\(localOff + 28\);
      const dataOff = localOff + 30 + localNameLen + localExtraLen;
      const raw = buf.subarray\(dataOff, dataOff + compSize\);

      if \(method === 0\) return raw;
      if \(method === 8\) return zlib.inflateRawSync\(raw\);
      throw new Error\('Unsupported method: ' + method\);
    }

    off += 46 + nameLen + extraLen + commentLen;
  }
  throw new Error\('Entry not found: ' + fileName\);
}

// Read package.xml
console.log\('=== package.xml ==='\);
console.log\(readZipEntry\(buf, 'package.xml'\).toString\('utf-8'\)\);

console.log\('\\\\n=== Switch.xml \(first 500 chars\) ==='\);
console.log\(readZipEntry\(buf, 'Switch.xml'\).toString\('utf-8'\).substring\(0, 500\)\);

console.log\('\\\\n=== Switch.mjs \(first 200 chars\) ==='\);
console.log\(readZipEntry\(buf, 'com/mendix/widget/custom/switch/Switch.mjs'\).toString\('utf-8'\).substring\(0, 200\)\);

console.log\('\\\\n=== Switch.mjs \(last 200 chars\) ==='\);
const mjs = readZipEntry\(buf, 'com/mendix/widget/custom/switch/Switch.mjs'\).toString\('utf-8'\);
console.log\(mjs.substring\(mjs.length - 200\)\);
")

